  // IMAGE CONTROLS (The Content Inside)
  imageRotation?: number;
  imageScale?: number;
  imageX?: number;
  imageY?: number;

  backgroundOpacity?: number; 
  borderWidth?: number;
  borderColor?: string;
  hasShadow?: boolean;
  hasTornEdges?: boolean; 
}

export interface SlideDefinition {
  template: string;
  image?: SlideImageConfig;
  overlayImage?: OverlayImageConfig; // Novo objeto visual flutuante
  options?: {
    theme?: 'dark' | 'light';
    background?: string;
    accent?: string;
    text?: string;
    cardBg?: string; 
    cardTextColor?: string; 
    cardOpacity?: number; 
    hlBgColor?: string; 
    hlTextColor?: string; 
    blockGap?: number; 
    sectionGap?: number; 
    padding?: number; 
    backgroundImage?: string;
    fontPadrão?: string; // New global font setting
    fontDestaque?: string; // New global font setting
    texture?: {
      type: 'grain' | 'paper' | 'dust' | 'none';
      amount: number;
      blendMode?: string;
    };
    postFX?: {
      noiseAmount?: number;
      noiseMode?: string;
      lightingIntensity?: number;
      clarity?: number;
      vignette?: number;
    };
  };
