}

export interface CustomFont {
  id: string;
  name: string;
  family: string;
  url: string;
}

export interface CarouselDefinition {
  slides: SlideDefinition[];
  customFonts?: CustomFont[];
}

export interface Theme {
  name: string;
  typography: {
    fontFamily: string;
    fontFamilySecondary?: string; // New
    hero: string;
    title: string;
    paragraph: string;
    body: string;
    small: string;
    titleWeight: string | number;
    letterSpacingTitle: string;
  };
  colors: {
    background: string;
    textPrimary: string;
    textSecondary: string;
    accent: string;
    muted: string;
    highlight: string;
    cardBg?: string; 
    cardTextColor?: string;
    cardOpacity?: number;
    hlBgColor?: string;
    hlTextColor?: string;
  };
  spacing: {
    canvasPadding: string;
    blockGap: string;
    sectionGap: string;
  };
  backgrounds: Record<string, any>;
}

import { z } from 'zod';

export const blockSchema = z.object({
  type: z.enum(['TITLE', 'LIST', 'IMAGE', 'SPACER', 'PARAGRAPH', 'CARD', 'BADGE', 'BOX', 'USER']),
  content: z.union([z.string(), z.array(z.string())]).optional(),
  options: z.object({
    highlight: z.string().optional(),
    variant: z.enum(['default', 'accent', 'muted', 'box', 'ghost', 'outlined', 'pill', 'oval', 'check-list', 'twitter-post']).optional(),
    size: z.enum(['sm', 'md', 'lg']).optional(),
    icon: z.string().optional(),
    customIcon: z.string().optional(),
    align: z.enum(['left', 'center', 'right']).optional(),
    fontSize: z.number().optional(),
    color: z.string().optional(),
    letterSpacing: z.number().optional(),
    lineHeight: z.number().optional(),
    textAlign: z.enum(['left', 'center', 'right']).optional(),
    fontFamily: z.string().optional(),
    fontVariant: z.enum(['padrão', 'destaque']).optional(),
    handle: z.string().optional(),
    avatar: z.string().optional(),
    handleColor: z.string().optional(),
    hideName: z.boolean().optional(),
    padding: z.number().optional(),
  }).optional(),
});

export const imageConfigSchema = z.object({
  type: z.enum(['IMAGE_SELECT', 'IMAGE_BACKGROUND', 'IMAGE_BOX', 'IMAGE_GLASS_CARD', 'IMAGE_SPLIT_HALF', 'NONE']),
  url: z.string().optional(),
  overlay: z.enum(['dark', 'blur-card', 'none']).optional(),
  boxOverlay: z.enum(['dark', 'light']).optional(),
  position: z.enum(['right', 'left', 'top', 'bottom']).optional(),
  format: z.enum(['png', 'jpg']).optional(),

  // Outer Box Transforms
  boxRotation: z.number().optional(),
  boxScale: z.number().optional(),
  boxX: z.number().optional(),
  boxY: z.number().optional(),
  width: z.number().optional(),

  // Inner Image Transforms
  imageRotation: z.number().optional(),
  imageScale: z.number().optional(),
  imageX: z.number().optional(),
  imageY: z.number().optional(),

  backgroundOpacity: z.number().min(0).max(1).optional(),
  borderWidth: z.number().optional(),
  borderColor: z.string().optional(),
  hasShadow: z.boolean().optional(),
});

export const overlayImageSchema = z.object({
  url: z.string().optional(),
  x: z.number().optional(),
  y: z.number().optional(),
  scale: z.number().optional(),
  rotation: z.number().optional(),
  opacity: z.number().optional(),
  isFlipped: z.boolean().optional(),
});

export const slideSchema = z.object({
  template: z.string(),
  image: imageConfigSchema.optional(),
  overlayImage: overlayImageSchema.optional(),
  options: z.object({
    theme: z.enum(['dark', 'light']).optional(),
    background: z.string().optional(),
    accent: z.string().optional(),
    text: z.string().optional(),
    cardBg: z.string().optional(),
    cardTextColor: z.string().optional(),
    cardOpacity: z.number().min(0).max(1).optional(),
    hlBgColor: z.string().optional(),
    hlTextColor: z.string().optional(),
    blockGap: z.number().optional(),
    sectionGap: z.number().optional(),
    padding: z.number().optional(),
    backgroundImage: z.string().url().optional(),
    fontPadrão: z.string().optional(),
    fontDestaque: z.string().optional(),
    texture: z.object({
      type: z.enum(['grain', 'paper', 'dust', 'none']),
      amount: z.number().min(0).max(1).optional(),
      blendMode: z.string().optional(),
    }).optional(),
    postFX: z.object({
      noiseAmount: z.number().min(0).max(1).optional(),
      noiseMode: z.string().optional(),
      lightingIntensity: z.number().min(0).max(1).optional(),
      clarity: z.number().min(0).max(1).optional(),
      vignette: z.number().min(0).max(1).optional(),
    }).optional(),
  }).optional(),
  blocks: z.array(blockSchema).max(15),
});

export const customFontSchema = z.object({
  id: z.string(),
  name: z.string(),
  family: z.string(),
  url: z.string().url(),
});

export const carouselSchema = z.object({
  slides: z.array(slideSchema).min(1).max(20),
  customFonts: z.array(customFontSchema).optional(),
});

export const templateDefSchema = z.object({
  name: z.string().min(3).max(40),
  description: z.string().min(10, "Description must be at least 10 characters."),
  layoutType: z.enum(['CENTERED', 'STACKED', 'SPLIT_IMAGE_TOP', 'SPLIT_IMAGE_SIDE', 'EDITORIAL', 'GRID']),
  allowedBlocks: z.array(z.enum(['TITLE', 'LIST', 'IMAGE', 'SPACER', 'PARAGRAPH', 'CARD', 'BADGE', 'BOX', 'USER'])).min(1),
  maxBlocks: z.number().optional(),
});

export type ValidatedCarousel = z.infer<typeof carouselSchema>;
export type ValidatedSlide = z.infer<typeof slideSchema>;
export type ValidatedTemplate = z.infer<typeof templateDefSchema>;

import React, { useMemo } from 'react'
import { ValidatedSlide } from '../template-dsl/schema'
import { TOKENS } from '../design-tokens/tokens'
import { renderBlock } from './renderBlock'
import { templateRegistry } from '../domain/templates/TemplateRegistry'
import { Image as ImageIcon, Box, User, Layers, Package } from 'lucide-react'
import { Block, CustomFont } from '../types'

export const SlideCanvas: React.FC<{ 
  slide: ValidatedSlide, 
  index: number, 
  canvasRef: React.RefObject<HTMLDivElement>,
  onEditIcon?: (block: Block, index: number) => void,
  customFonts?: CustomFont[]
}> = ({ slide, index, canvasRef, onEditIcon, customFonts }) => {
  const isLight = slide.options?.theme === 'light'
  const templateDef = templateRegistry.get(slide.template)

  const theme = useMemo(() => {
    const baseBackground = isLight ? '#F2F2F2' : '#0D0D0D'
    const baseTextPrimary = isLight ? '#000000' : '#FFFFFF'
    const baseTextSecondary = isLight ? '#333333' : 'rgba(255, 255, 255, 0.9)'

    return {
      ...TOKENS,
      typography: {
        ...TOKENS.typography,
        fontFamily: slide.options?.fontPadrão || TOKENS.typography.fontFamily,
        fontFamilySecondary: slide.options?.fontDestaque || '"Instrument Serif", serif',
      },
      colors: {
        ...TOKENS.colors,
        background: slide.options?.background || baseBackground,
        textPrimary: slide.options?.text || baseTextPrimary,
        textSecondary: slide.options?.text ? `${slide.options.text}cc` : baseTextSecondary,
        accent: slide.options?.accent || TOKENS.colors.accent,
        highlight: slide.options?.accent || TOKENS.colors.highlight,
        cardBg: slide.options?.cardBg || slide.options?.accent || TOKENS.colors.accent,
        cardTextColor: slide.options?.cardTextColor,
        cardOpacity: slide.options?.cardOpacity !== undefined ? slide.options.cardOpacity : 1,
        hlBgColor: slide.options?.hlBgColor || slide.options?.accent || TOKENS.colors.accent,
        hlTextColor: slide.options?.hlTextColor || '#000000',
      }
    }
  }, [isLight, slide.options?.background, slide.options?.accent, slide.options?.text, slide.options?.cardBg, slide.options?.cardTextColor, slide.options?.cardOpacity, slide.options?.hlBgColor, slide.options?.hlTextColor, slide.options?.fontPadrão, slide.options?.fontDestaque])

  if (!templateDef) return <div ref={canvasRef} className="w-[1080px] h-[1350px] bg-red-900 flex items-center justify-center text-white font-bold">ERROR: TEMPLATE NOT FOUND</div>

  const imageConfig = slide.image;
  const overlayImage = slide.overlayImage;
  const texture = slide.options?.texture;
  const fx = slide.options?.postFX;

  const blockGap = slide.options?.blockGap !== undefined ? slide.options.blockGap : 16;
  const sectionGap = slide.options?.sectionGap !== undefined ? slide.options.sectionGap : 48;
  const padding = slide.options?.padding !== undefined ? slide.options.padding : 80;

  const renderTornPaperSVG = () => {
    if (!imageConfig?.hasTornEdges) return null;
    const maskId = `tornMask-${index}`;
    return (
      <svg width="0" height="0" className="absolute">
        <defs>
          <clipPath id={maskId} clipPathUnits="objectBoundingBox">
            <path d="M0.04,0.06 C0.1,0.04 0.15,0.08 0.2,0.05 C0.25,0.03 0.3,0.07 0.35,0.04 C0.4,0.02 0.45,0.06 0.5,0.04 C0.55,0.03 0.6,0.07 0.65,0.05 C0.7,0.03 0.75,0.06 0.8,0.04 C0.85,0.03 0.9,0.07 0.96,0.05 C0.98,0.1 0.95,0.15 0.97,0.2 C0.99,0.25 0.96,0.3 0.98,0.35 C1.0,0.4 0.97,0.45 0.99,0.5 C1.0,0.55 0.96,0.6 0.98,0.65 C1.0,0.7 0.97,0.75 0.99,0.8 C1.0,0.85 0.96,0.9 0.94,0.96 C0.9,0.98 0.85,0.95 0.8,0.97 C0.75,0.99 0.7,0.96 0.65,0.98 C0.6,1.0 0.55,0.97 0.5,0.99 C0.45,1.0 0.4,0.96 0.35,0.98 C0.3,1.0 0.25,0.97 0.2,0.99 C0.15,1.0 0.1,0.96 0.04,0.94 C0.02,0.9 0.05,0.85 0.03,0.8 C0.01,0.75 0.04,0.7 0.02,0.65 C0.0,0.6 0.03,0.55 0.01,0.5 C0.0,0.45 0.04,0.4 0.02,0.35 C0.0,0.3 0.03,0.25 0.01,0.2 C0.0,0.15 0.04,0.1 0.04,0.06 Z" />
          </clipPath>
        </defs>
      </svg>
    );
  };

  const renderImage = (className: string, fit: 'cover' | 'contain' = 'cover', extraStyle: React.CSSProperties = {}) => {
    if (!imageConfig?.url) return null;
    const imgScale = imageConfig.imageScale ?? 1;
    const imgRotation = imageConfig.imageRotation ?? 0;
    const imgX = imageConfig.imageX ?? 0;
    const imgY = imageConfig.imageY ?? 0;
    const opacity = imageConfig.backgroundOpacity ?? 1;
    const maskId = `tornMask-${index}`;
    return (
      <div className={`${className} transition-all duration-300 ease-out`} style={{ clipPath: imageConfig.hasTornEdges ? `url(#${maskId})` : 'none', ...extraStyle }}>
        <img src={imageConfig.url} className={`w-full h-full ${fit === 'cover' ? 'object-cover' : 'object-contain'}`} style={{ objectPosition: `calc(50% + ${imgX}px) calc(50% + ${imgY}px)`, transform: `scale(${imgScale}) rotate(${imgRotation}deg)`, transformOrigin: 'center', opacity: opacity }} alt="" />
      </div>
    );
  };

  const renderFloatingOverlay = () => {
    if (!overlayImage?.url) return null;
    return (
      <div 
        className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center overflow-hidden"
      >
        <img 
          src={overlayImage.url} 
          className="max-w-none transition-all duration-300 ease-out"
          style={{ 
            transform: `translate(${overlayImage.x || 0}px, ${overlayImage.y || 0}px) scale(${overlayImage.scale || 1}) scaleX(${overlayImage.isFlipped ? -1 : 1}) rotate(${overlayImage.rotation || 0}deg)`,
            opacity: overlayImage.opacity ?? 1,
            pointerEvents: 'none'
          }}
          alt="Floating Overlay"
        />
      </div>
    );
  };

  const renderBlocks = () => (
    <div className="w-full relative z-30 flex flex-col" style={{ gap: `${blockGap}px` }}>
      {slide.blocks.map((b, i) => <React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, false, 0, i)}</React.Fragment>)}
    </div>
  );

  const renderFXOverlays = () => {
    const overlays: React.ReactNode[] = [];
    const fxId = `fx-${index}`;
    if (fx?.lightingIntensity && fx.lightingIntensity > 0) overlays.push(<div key="fx-lighting" className="absolute inset-0 pointer-events-none z-[42]" style={{ background: `radial-gradient(circle at 30% 20%, rgba(255,255,255,${fx.lightingIntensity * 0.15}), transparent 80%)`, mixBlendMode: 'screen' }} />);
    if (fx?.vignette && fx.vignette > 0) overlays.push(<div key="fx-vignette" className="absolute inset-0 pointer-events-none z-[48]" style={{ background: `radial-gradient(circle, transparent 40%, rgba(0,0,0,${fx.vignette * 0.6}) 100%)`, mixBlendMode: 'multiply' }} />);
    if (fx?.noiseAmount && fx.noiseAmount > 0) overlays.push(<div key="fx-noise" className="absolute inset-0 pointer-events-none z-[49]" style={{ opacity: fx.noiseAmount, mixBlendMode: (fx.noiseMode as any) || 'multiply' }}><svg width="100%" height="100%"><filter id={`${fxId}-noise`}><feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch" /><feColorMatrix type="saturate" values="0" /></filter><rect width="100%" height="100%" filter={`url(#${fxId}-noise)`} fill="transparent" /></svg></div>);
    return overlays;
  };

  const renderLayout = () => {
    const canvasPadding = `${padding}px`;
    const bRot = imageConfig?.boxRotation ?? 0;
    const bScale = imageConfig?.boxScale ?? 1;
    const bX = imageConfig?.boxX ?? 0;
    const bY = imageConfig?.boxY ?? 0;
    const boxWidth = imageConfig?.width || 480;
    const isFloatingBox = imageConfig?.type === 'IMAGE_BOX' || imageConfig?.type === 'IMAGE_GLASS_CARD';

    const imageBoxStyle: React.CSSProperties = {
      border: imageConfig?.borderWidth && isFloatingBox ? `${imageConfig.borderWidth}px solid ${imageConfig.borderColor || '#FFFFFF'}` : 'none',
      boxShadow: imageConfig?.hasShadow && isFloatingBox ? `0 ${imageConfig.hasTornEdges ? '30px 80px' : '40px 120px'} -20px rgba(0,0,0,${imageConfig.hasTornEdges ? '0.15' : '0.8'}), 0 0 100px ${imageConfig.borderColor || theme.colors.accent}${imageConfig.hasTornEdges ? '10' : '40'}` : 'none',
      transform: isFloatingBox ? `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` : undefined,
      transformOrigin: 'center',
      width: imageConfig?.type === 'IMAGE_BOX' ? `${boxWidth}px` : undefined,
      flexShrink: 0
    };

    const clarityIntensity = fx?.clarity || 0;
    const contentFilter = clarityIntensity > 0 ? `contrast(${1 + clarityIntensity * 0.25}) saturate(${1 + clarityIntensity * 0.15}) brightness(${1 - clarityIntensity * 0.05})` : 'none';

    const renderLayoutInternal = () => {
      if (templateDef.name === 'CARD_BOX' || templateDef.name === 'BENTO_SHOWCASE') {
        const boxBlocks = slide.blocks.filter(b => b.type === 'BOX');
        const otherBlocks = slide.blocks.filter(b => b.type !== 'BOX');
        return (<div className="relative h-full w-full flex flex-col justify-center items-center" style={{ padding: canvasPadding }}>{otherBlocks.length > 0 && (<div className="mb-12 w-full flex flex-col gap-8">{otherBlocks.map((b, i) => (<React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, false, 0, slide.blocks.indexOf(b))}</React.Fragment>))}</div>)}<div className="grid grid-cols-2 gap-10 w-full">{boxBlocks.map((b, i) => (<React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, true, i, slide.blocks.indexOf(b))}</React.Fragment>))}</div></div>);
      }
      if (imageConfig?.type === 'IMAGE_BOX') {
          const pos = imageConfig.position || 'right';
          const isHorizontal = pos === 'left' || pos === 'right';
          if (isHorizontal) {
            const isRight = pos === 'right';
            return (<div className={`relative h-full w-full flex items-center ${isRight ? 'flex-row' : 'flex-row-reverse'}`} style={{ padding: canvasPadding, gap: `${sectionGap}px` }}><div className="flex-1 min-w-0 z-20">{renderBlocks()}</div><div style={imageBoxStyle} className={`h-[850px] relative transition-all duration-300 z-10 bg-zinc-800 rounded-[50px] overflow-hidden border-4 border-white/10`}>{imageConfig.url ? (renderImage("w-full h-full", "cover")) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Box size={100} /></div>)}</div></div>);
          } else {
            const isBottom = pos === 'bottom';
            return (<div className={`relative h-full w-full flex flex-col items-center ${isBottom ? 'flex-col' : 'flex-col-reverse'}`} style={{ padding: canvasPadding, gap: `${sectionGap}px` }}><div className="flex-1 w-full flex flex-col justify-center z-20">{renderBlocks()}</div><div style={{ ...imageBoxStyle, height: '400px', width: '80%' }} className={`relative transition-all duration-300 z-10 bg-zinc-800 rounded-[50px] overflow-hidden border-4 border-white/10`}>{imageConfig.url ? (renderImage("w-full h-full", "cover")) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Box size={100} /></div>)}</div></div>);
          }
      }
      if (imageConfig?.type === 'IMAGE_GLASS_CARD' || templateDef.name === 'GLASS_OVERLAY' || templateDef.name === 'PREMIUM_GLASS') {
        const isDarkBox = imageConfig?.boxOverlay === 'dark';
        return (<div className="relative h-full w-full"><div className="absolute inset-0 overflow-hidden z-0 bg-zinc-900">{imageConfig?.url ? renderImage("w-full h-full", "cover") : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><ImageIcon size={100} /></div>)}</div><div className="relative z-10 h-full w-full flex flex-col justify-center items-center" style={{ padding: canvasPadding }}><div style={{ ...imageBoxStyle, width: '100%', maxWidth: '840px' }} className={`backdrop-blur-[20px] saturate-[160%] p-20 rounded-[80px] border border-white/30 transition-colors duration-500 ${isDarkBox ? 'bg-black/60' : 'bg-white/5'}`}>{renderBlocks()}</div></div></div>);
      }
      if (imageConfig?.type === 'IMAGE_SPLIT_HALF' || templateDef.name === 'ASPECT_EDITORIAL' || templateDef.name === 'SPLIT_EDITORIAL') {
        const pos = imageConfig?.position || 'right';
        const isSideBySide = pos === 'left' || pos === 'right';
        const isVertical = pos === 'top' || pos === 'bottom';
        const isRightOrBottom = pos === 'right' || pos === 'bottom';
        if (isSideBySide) return (<div className={`relative h-full w-full flex ${isRightOrBottom ? 'flex-row' : 'flex-row-reverse'}`} style={{ backgroundColor: theme.colors.background }}><div className="flex-1 h-full flex flex-col justify-center px-24 z-20 min-w-0">{renderBlocks()}</div><div className="flex-1 h-full relative overflow-hidden bg-zinc-900 border-x border-white/5 z-10 transition-all">{imageConfig?.url ? renderImage("w-full h-full", "cover", { transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` }) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Layers size={100} /></div>)}</div></div>); 
        if (isVertical) return (<div className={`relative h-full w-full flex flex-col ${isRightOrBottom ? 'flex-col' : 'flex-col-reverse'}`} style={{ backgroundColor: theme.colors.background }}><div className="flex-1 w-full flex flex-col justify-center z-20" style={{ padding: canvasPadding }}><div className="max-w-[840px] mx-auto w-full">{renderBlocks()}</div></div><div className="w-full h-1/2 overflow-hidden relative border-y border-white/5 z-10 transition-all">{imageConfig?.url ? renderImage("w-full h-full", "cover", { transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` }) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Layers size={100} /></div>)}</div></div>); 
      }

      const isFullBg = imageConfig?.type === 'IMAGE_BACKGROUND' || imageConfig?.type === 'IMAGE_SELECT' || templateDef.name === 'MEGA_STATEMENT' || templateDef.name === 'CINEMATIC_BG' || templateDef.name === 'HERO_STATEMENT';
      const isSocialPost = templateDef.name === 'SOCIAL_CHECKLIST';
      return (<div className="relative h-full w-full overflow-hidden">{isFullBg && (<div className="absolute inset-0 overflow-hidden z-0 w-full h-full">{imageConfig?.url ? renderImage("w-full h-full", "cover", { transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` }) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><ImageIcon size={100}/></div>)}{imageConfig?.overlay === 'dark' && <div className="absolute inset-0 bg-black/60" />}</div>)}<div className="relative z-10 h-full w-full flex flex-col justify-center items-start" style={{ padding: canvasPadding }}><div className={`w-full max-w-[840px] mx-auto flex flex-col justify-center min-h-0 ${isSocialPost ? 'border border-white/10 rounded-[40px] p-16 bg-white/5' : ''}`}>{renderBlocks()}</div></div></div>);
    };
    return (<div style={{ filter: contentFilter }} className="h-full w-full overflow-hidden">{renderLayoutInternal()}</div>);
  };

  const customFontsCSS = useMemo(() => {
    if (!customFonts || customFonts.length === 0) return '';
    return customFonts.map(f => `@font-face { font-family: '${f.family}'; src: url('${f.url}'); font-display: swap; font-weight: normal; font-style: normal; }`).join('\n');
  }, [customFonts]);

  return (
    <div ref={canvasRef} style={{ backgroundColor: theme.colors.background, color: theme.colors.textPrimary, fontFamily: theme.typography.fontFamily }} className="relative w-[1080px] h-[1350px] flex flex-col shadow-2xl overflow-hidden shrink-0 select-auto">
      <style dangerouslySetInnerHTML={{ __html: customFontsCSS }} />
      {slide.options?.backgroundImage && (
        <div className="absolute inset-0 z-0 w-full h-full pointer-events-none">
          <img src={slide.options.backgroundImage} className="w-full h-full object-cover" alt="" />
        </div>
      )}
      {renderTornPaperSVG()}
      {renderLayout()}
      {renderFloatingOverlay()}
      {renderFXOverlays()}
    </div>
  )
}

