                  {uploadedBackgrounds.length > 0 && (<div className="space-y-3"><span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest px-1">Sua Biblioteca</span><div className="grid grid-cols-4 gap-3">{uploadedBackgrounds.map((bg, idx) => (<button key={idx} onClick={() => updateSlideProperty(['options', 'backgroundImage'], bg)} className={`aspect-[4/5] rounded-xl overflow-hidden border-2 transition-all ${currentSlide?.options?.backgroundImage === bg ? 'border-brand scale-105 shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}`}><img src={bg} className="w-full h-full object-cover" /></button>))}</div></div>)}
                </section>
              </div>
            ) : activeTab === 'TEMPLATES' ? (
              <div className="grid grid-cols-1 gap-2">{templates.map(tpl => (<button key={tpl.name} onClick={() => updateSlideProperty(['template'], tpl.name)} className={`w-full p-4 border rounded-2xl flex items-center gap-4 transition-all ${currentSlide?.template === tpl.name ? 'bg-brand/10 border-brand' : 'bg-white/5 border-white/5 hover:border-white/10'}`}><div className={`w-10 h-10 rounded-xl flex items-center justify-center ${currentSlide?.template === tpl.name ? 'bg-brand text-black' : 'bg-black text-zinc-600'}`}><Library size={18}/></div><div className="text-left"><p className={`text-[10px] font-black uppercase ${currentSlide?.template === tpl.name ? 'text-brand' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p><p className="text-[8px] text-zinc-600 font-medium truncate max-w-[200px]">{tpl.description}</p></div></button>))}</div>
            ) : activeTab === 'JSON' ? (
              <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="w-full h-[600px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-2xl outline-none custom-scrollbar" spellCheck={false} />
            ) : null}
          </div>
          <footer className="p-5 border-t border-white/5 bg-zinc-950"><button onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="w-full py-4 bg-brand text-black font-black rounded-xl text-[10px] uppercase shadow-lg flex items-center justify-center gap-3 active:scale-95"><Download size={16} strokeWidth={3} /> Exportar Tudo</button></footer>
        </aside>
        <main className="flex-1 bg-[#121214] relative flex flex-col">
          {error && <div className="absolute top-5 left-1/2 -translate-x-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-2xl flex items-center gap-3 shadow-2xl animate-in slide-in-from-top-4"><AlertCircle size={18}/><span className="text-[11px] font-black uppercase">{error}</span></div>}
          <div className="absolute left-6 top-1/2 -translate-y-1/2 z-40 flex flex-col items-center gap-4 bg-black/40 backdrop-blur-2xl p-3 rounded-[32px] border border-white/10 shadow-2xl transition-all hover:bg-black/60"><button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-3 text-zinc-400 hover:text-brand hover:bg-brand/10 rounded-full transition-all active:scale-90" title="Zoom In"><ZoomIn size={20} /></button><div className="w-8 h-[1px] bg-white/10" /><div className="text-[10px] font-black font-mono text-zinc-500 py-1 select-none">{(zoom * 100).toFixed(0)}%</div><div className="w-8 h-[1px] bg-white/10" /><button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-3 text-zinc-400 hover:text-brand hover:bg-brand/10 rounded-full transition-all active:scale-90" title="Zoom Out"><ZoomOut size={20} /></button></div>
          <div className="absolute top-5 right-5 z-40 flex items-center gap-1 bg-black/30 backdrop-blur-xl p-1.5 rounded-xl border border-white/5"><button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-1.5 text-zinc-500 hover:text-white"><ZoomOut size={16} /></button><div className="px-2 text-[10px] font-black font-mono text-zinc-400">{(zoom * 100).toFixed(0)}%</div><button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-1.5 text-zinc-500 hover:text-white"><ZoomIn size={16} /></button></div>
          <div className="flex-1 flex items-center justify-center overflow-auto p-20" onMouseUp={handleCanvasMouseUp}><div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_60px_150px_rgba(0,0,0,0.8)] shrink-0">{carousel?.slides?.[currentIndex] && <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} onEditIcon={(b, i) => setEditingIconBlock({ block: b, index: i })} customFonts={carousel.customFonts} />}</div></div>
          {carousel && carousel.slides.length > 0 && (<div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-6 bg-black/50 backdrop-blur-2xl px-8 py-4 rounded-full border border-white/5 shadow-2xl transition-all hover:border-white/10"><button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronLeft size={20}/></button><div className="flex gap-2.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-brand' : 'w-2 bg-white/10 hover:bg-white/20'}`} />))}</div><button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronRight size={20}/></button></div>)}
        </main>
      </div>
    </div>
  );
};

export default App;

export type BlockType = 'TITLE' | 'LIST' | 'IMAGE' | 'SPACER' | 'PARAGRAPH' | 'CARD' | 'BADGE' | 'BOX' | 'USER';

export interface Block {
  type: BlockType;
  content?: string | string[];
  options?: {
    highlight?: string;
    variant?: 'default' | 'accent' | 'muted' | 'box' | 'ghost' | 'outlined' | 'pill' | 'oval' | 'check-list' | 'twitter-post';
    size?: 'sm' | 'md' | 'lg';
    icon?: string;
    customIcon?: string; 
    align?: 'left' | 'center' | 'right';
    fontSize?: number;
    color?: string;
    letterSpacing?: number;
    lineHeight?: number;
    textAlign?: 'left' | 'center' | 'right';
    fontFamily?: 'sans' | 'serif' | string;
    fontVariant?: 'padrão' | 'destaque';
    handle?: string;
    avatar?: string;
    handleColor?: string;
    hideName?: boolean;
    padding?: number;
  };
}

export interface OverlayImageConfig {
  id: string;
  url: string;
  x?: number;
  y?: number;
  scale?: number;
  rotation?: number;
  opacity?: number;
  isFlipped?: boolean;
}

export interface SlideImageConfig {
  type: 'IMAGE_SELECT' | 'IMAGE_BACKGROUND' | 'IMAGE_BOX' | 'IMAGE_GLASS_CARD' | 'IMAGE_SPLIT_HALF' | 'NONE';
  url?: string;
  overlay?: 'dark' | 'blur-card' | 'none';
  boxOverlay?: 'dark' | 'light';
  position?: 'right' | 'left' | 'top' | 'bottom';
  boxRotation?: number;
  boxScale?: number;
  boxX?: number;
  boxY?: number;
  width?: number;
  imageRotation?: number;
  imageScale?: number;
  imageX?: number;
  imageY?: number;
  backgroundOpacity?: number; 
  borderWidth?: number;
  borderColor?: string;
  hasShadow?: boolean;
  hasTornEdges?: boolean; 
}

export interface SlideDefinition {
  template: string;
  image?: SlideImageConfig;
  overlays?: OverlayImageConfig[]; 
  options?: {
    theme?: 'dark' | 'light';
    background?: string;
    accent?: string;
    text?: string;
    cardBg?: string; 
    cardTextColor?: string; 
    cardOpacity?: number; 
    hlBgColor?: string; 
    hlTextColor?: string; 
    blockGap?: number; 
    sectionGap?: number; 
    padding?: number; 
    backgroundImage?: string;
    fontPadrão?: string;
    fontDestaque?: string;
    texture?: {
      type: 'grain' | 'paper' | 'dust' | 'none';
      amount: number;
    };
    postFX?: {
      noiseAmount?: number;
      lightingIntensity?: number;
      clarity?: number;
      vignette?: number;
    };
  };
  blocks: Block[];
}

export interface CustomFont {
  id: string;
  name: string;
  family: string;
  url: string;
}

export interface CarouselDefinition {
  slides: SlideDefinition[];
  customFonts?: CustomFont[];
}

export interface Theme {
  name: string;
  typography: {
    fontFamily: string;
    fontFamilySecondary?: string;
    hero: string;
    title: string;
    paragraph: string;
    body: string;
    small: string;
    titleWeight: string | number;
    letterSpacingTitle: string;
  };
  colors: {
    background: string;
    textPrimary: string;
    textSecondary: string;
    accent: string;
    muted: string;
    highlight: string;
    cardBg?: string; 
    cardTextColor?: string;
    cardOpacity?: number;
    hlBgColor?: string;
    hlTextColor?: string;
  };
  spacing: {
    canvasPadding: string;
    blockGap: string;
    sectionGap: string;
  };
  backgrounds: Record<string, any>;
}

import React, { useMemo } from 'react'
import { ValidatedSlide } from '../template-dsl/schema'
import { TOKENS } from '../design-tokens/tokens'
import { renderBlock } from './renderBlock'
import { templateRegistry } from '../domain/templates/TemplateRegistry'
import { Image as ImageIcon, Box, User, Layers } from 'lucide-react'
import { Block, CustomFont } from '../types'

export const SlideCanvas: React.FC<{ 
  slide: ValidatedSlide, 
  index: number, 
  canvasRef: React.RefObject<HTMLDivElement>,
  onEditIcon?: (block: Block, index: number) => void,
  customFonts?: CustomFont[]
}> = ({ slide, index, canvasRef, onEditIcon, customFonts }) => {
  const isLight = slide.options?.theme === 'light'
  const templateDef = templateRegistry.get(slide.template)

  const theme = useMemo(() => {
    const baseBackground = isLight ? '#F2F2F2' : '#0D0D0D'
    const baseTextPrimary = isLight ? '#000000' : '#FFFFFF'
    const baseTextSecondary = isLight ? '#333333' : 'rgba(255, 255, 255, 0.9)'

    return {
      ...TOKENS,
      typography: {
        ...TOKENS.typography,
        fontFamily: slide.options?.fontPadrão || TOKENS.typography.fontFamily,
        fontFamilySecondary: slide.options?.fontDestaque || '"Instrument Serif", serif',
      },
      colors: {
        ...TOKENS.colors,
        background: slide.options?.background || baseBackground,
        textPrimary: slide.options?.text || baseTextPrimary,
        textSecondary: slide.options?.text ? `${slide.options.text}cc` : baseTextSecondary,
        accent: slide.options?.accent || TOKENS.colors.accent,
        highlight: slide.options?.accent || TOKENS.colors.highlight,
        cardBg: slide.options?.cardBg || slide.options?.accent || TOKENS.colors.accent,
        cardTextColor: slide.options?.cardTextColor,
        cardOpacity: slide.options?.cardOpacity !== undefined ? slide.options.cardOpacity : 1,
        hlBgColor: slide.options?.hlBgColor || slide.options?.accent || TOKENS.colors.accent,
        hlTextColor: slide.options?.hlTextColor || '#000000',
      }
    }
  }, [isLight, slide.options?.background, slide.options?.accent, slide.options?.text, slide.options?.cardBg, slide.options?.cardTextColor, slide.options?.cardOpacity, slide.options?.hlBgColor, slide.options?.hlTextColor, slide.options?.fontPadrão, slide.options?.fontDestaque])

  if (!templateDef) return <div ref={canvasRef} className="w-[1080px] h-[1350px] bg-red-900 flex items-center justify-center text-white font-bold">ERROR: TEMPLATE NOT FOUND</div>

  const imageConfig = slide.image;
  const overlays = slide.overlays || [];
  const fx = slide.options?.postFX;

  const renderImage = (className: string, fit: 'cover' | 'contain' = 'cover', extraStyle: React.CSSProperties = {}) => {
    if (!imageConfig?.url) return null;
    const imgScale = imageConfig.imageScale ?? 1;
    const imgRotation = imageConfig.imageRotation ?? 0;
    const imgX = imageConfig.imageX ?? 0;
    const imgY = imageConfig.imageY ?? 0;
    const opacity = imageConfig.backgroundOpacity ?? 1;
    return (
      <div className={`${className} transition-all duration-300 ease-out`} style={extraStyle}>
        <img src={imageConfig.url} className={`w-full h-full ${fit === 'cover' ? 'object-cover' : 'object-contain'}`} style={{ objectPosition: `calc(50% + ${imgX}px) calc(50% + ${imgY}px)`, transform: `scale(${imgScale}) rotate(${imgRotation}deg)`, transformOrigin: 'center', opacity: opacity }} alt="" />
      </div>
    );
  };

  const renderFloatingOverlays = () => {
    return overlays.map((ov) => (
      <div 
        key={ov.id}
        className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center overflow-hidden"
      >
        <img 
          src={ov.url} 
          className="max-w-none transition-all duration-300 ease-out"
          style={{ 
            transform: `translate(${ov.x || 0}px, ${ov.y || 0}px) scale(${ov.scale || 1}) scaleX(${ov.isFlipped ? -1 : 1}) rotate(${ov.rotation || 0}deg)`,
            opacity: ov.opacity ?? 1,
            pointerEvents: 'none'
          }}
          alt="Overlay Object"
        />
      </div>
    ));
  };

  const renderBlocks = () => (
    <div className="w-full relative z-30 flex flex-col" style={{ gap: `${slide.options?.blockGap ?? 16}px` }}>
      {slide.blocks.map((b, i) => <React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, false, 0, i)}</React.Fragment>)}
    </div>
  );

  const renderFX = () => {
    const fxId = `fx-${index}`;
    return (
      <>
        {fx?.lightingIntensity && fx.lightingIntensity > 0 && <div className="absolute inset-0 pointer-events-none z-[42]" style={{ background: `radial-gradient(circle at 30% 20%, rgba(255,255,255,${fx.lightingIntensity * 0.15}), transparent 80%)`, mixBlendMode: 'screen' }} />}
        {fx?.vignette && fx.vignette > 0 && <div className="absolute inset-0 pointer-events-none z-[48]" style={{ background: `radial-gradient(circle, transparent 40%, rgba(0,0,0,${fx.vignette * 0.6}) 100%)`, mixBlendMode: 'multiply' }} />}
        {fx?.noiseAmount && fx.noiseAmount > 0 && <div className="absolute inset-0 pointer-events-none z-[49]" style={{ opacity: fx.noiseAmount, mixBlendMode: 'multiply' }}><svg width="100%" height="100%"><filter id={`${fxId}-noise`}><feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch" /><feColorMatrix type="saturate" values="0" /></filter><rect width="100%" height="100%" filter={`url(#${fxId}-noise)`} fill="transparent" /></svg></div>}
      </>
    );
  };

  const renderLayout = () => {
    const padding = slide.options?.padding ?? 80;
    const canvasPadding = `${padding}px`;
    const bRot = imageConfig?.boxRotation ?? 0;
    const bScale = imageConfig?.boxScale ?? 1;
    const bX = imageConfig?.boxX ?? 0;
    const bY = imageConfig?.boxY ?? 0;

    const imageBoxStyle: React.CSSProperties = {
      transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)`,
      transformOrigin: 'center',
      flexShrink: 0
    };

    const clarity = fx?.clarity || 0;
    const filter = clarity > 0 ? `contrast(${1 + clarity * 0.25}) saturate(${1 + clarity * 0.15}) brightness(${1 - clarity * 0.05})` : 'none';

    const content = (() => {
      if (templateDef.name === 'CARD_BOX' || templateDef.name === 'BENTO_SHOWCASE') {
        const boxBlocks = slide.blocks.filter(b => b.type === 'BOX');
        const otherBlocks = slide.blocks.filter(b => b.type !== 'BOX');
        return (<div className="relative h-full w-full flex flex-col justify-center items-center" style={{ padding: canvasPadding }}>{otherBlocks.length > 0 && (<div className="mb-12 w-full flex flex-col gap-8">{otherBlocks.map((b, i) => (<React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, false, 0, slide.blocks.indexOf(b))}</React.Fragment>))}</div>)}<div className="grid grid-cols-2 gap-10 w-full">{boxBlocks.map((b, i) => (<React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, true, i, slide.blocks.indexOf(b))}</React.Fragment>))}</div></div>);
      }
      if (imageConfig?.type === 'IMAGE_BOX') {
          const pos = imageConfig.position || 'right';
          const isHorizontal = pos === 'left' || pos === 'right';
          if (isHorizontal) {
            return (<div className={`relative h-full w-full flex items-center ${pos === 'right' ? 'flex-row' : 'flex-row-reverse'}`} style={{ padding: canvasPadding, gap: '48px' }}><div className="flex-1 min-w-0 z-20">{renderBlocks()}</div><div style={{ ...imageBoxStyle, height: '850px', width: '480px' }} className={`relative transition-all duration-300 z-10 bg-zinc-800 rounded-[50px] overflow-hidden border-4 border-white/10`}>{imageConfig.url ? (renderImage("w-full h-full", "cover")) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Box size={100} /></div>)}</div></div>);
          } else {
            return (<div className={`relative h-full w-full flex flex-col items-center ${pos === 'bottom' ? 'flex-col' : 'flex-col-reverse'}`} style={{ padding: canvasPadding, gap: '48px' }}><div className="flex-1 w-full flex flex-col justify-center z-20">{renderBlocks()}</div><div style={{ ...imageBoxStyle, height: '400px', width: '80%' }} className={`relative transition-all duration-300 z-10 bg-zinc-800 rounded-[50px] overflow-hidden border-4 border-white/10`}>{imageConfig.url ? (renderImage("w-full h-full", "cover")) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Box size={100} /></div>)}</div></div>);
          }
      }
      if (imageConfig?.type === 'IMAGE_GLASS_CARD' || templateDef.name === 'GLASS_OVERLAY' || templateDef.name === 'PREMIUM_GLASS') {
        const isDarkBox = imageConfig?.boxOverlay === 'dark';
        return (<div className="relative h-full w-full"><div className="absolute inset-0 overflow-hidden z-0 bg-zinc-900">{imageConfig?.url ? renderImage("w-full h-full", "cover") : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><ImageIcon size={100} /></div>)}</div><div className="relative z-10 h-full w-full flex flex-col justify-center items-center" style={{ padding: canvasPadding }}><div style={{ ...imageBoxStyle, width: '100%', maxWidth: '840px' }} className={`backdrop-blur-[20px] saturate-[160%] p-20 rounded-[80px] border border-white/30 transition-colors duration-500 ${isDarkBox ? 'bg-black/60' : 'bg-white/5'}`}>{renderBlocks()}</div></div></div>);
      }
      if (imageConfig?.type === 'IMAGE_SPLIT_HALF' || templateDef.name === 'ASPECT_EDITORIAL' || templateDef.name === 'SPLIT_EDITORIAL') {
        const pos = imageConfig?.position || 'right';
        const isSideBySide = pos === 'left' || pos === 'right';
        const isRightOrBottom = pos === 'right' || pos === 'bottom';
        if (isSideBySide) return (<div className={`relative h-full w-full flex ${isRightOrBottom ? 'flex-row' : 'flex-row-reverse'}`} style={{ backgroundColor: theme.colors.background }}><div className="flex-1 h-full flex flex-col justify-center px-24 z-20 min-w-0">{renderBlocks()}</div><div className="flex-1 h-full relative overflow-hidden bg-zinc-900 border-x border-white/5 z-10 transition-all">{imageConfig?.url ? renderImage("w-full h-full", "cover", { transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` }) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Layers size={100} /></div>)}</div></div>); 
        return (<div className={`relative h-full w-full flex flex-col ${isRightOrBottom ? 'flex-col' : 'flex-col-reverse'}`} style={{ backgroundColor: theme.colors.background }}><div className="flex-1 w-full flex flex-col justify-center z-20" style={{ padding: canvasPadding }}><div className="max-w-[840px] mx-auto w-full">{renderBlocks()}</div></div><div className="w-full h-1/2 overflow-hidden relative border-y border-white/5 z-10 transition-all">{imageConfig?.url ? renderImage("w-full h-full", "cover", { transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` }) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><Layers size={100} /></div>)}</div></div>); 
      }

      const isFullBg = imageConfig?.type === 'IMAGE_BACKGROUND' || imageConfig?.type === 'IMAGE_SELECT' || templateDef.name === 'MEGA_STATEMENT' || templateDef.name === 'CINEMATIC_BG' || templateDef.name === 'HERO_STATEMENT';
      return (<div className="relative h-full w-full overflow-hidden">{isFullBg && (<div className="absolute inset-0 overflow-hidden z-0 w-full h-full">{imageConfig?.url ? renderImage("w-full h-full", "cover", { transform: `translate(${bX}px, ${bY}px) scale(${bScale}) rotate(${bRot}deg)` }) : (<div className="w-full h-full bg-black/40 flex items-center justify-center text-white/10"><ImageIcon size={100}/></div>)}{imageConfig?.overlay === 'dark' && <div className="absolute inset-0 bg-black/60" />}</div>)}<div className="relative z-10 h-full w-full flex flex-col justify-center items-start" style={{ padding: canvasPadding }}><div className={`w-full max-w-[840px] mx-auto flex flex-col justify-center min-h-0`}>{renderBlocks()}</div></div></div>);
    })();

    return (<div style={{ filter }} className="h-full w-full overflow-hidden">{content}</div>);
  };

  const customFontsCSS = useMemo(() => {
    if (!customFonts || customFonts.length === 0) return '';
    return customFonts.map(f => `@font-face { font-family: '${f.family}'; src: url('${f.url}'); font-display: swap; }`).join('\n');
  }, [customFonts]);

  return (
    <div ref={canvasRef} style={{ backgroundColor: theme.colors.background, color: theme.colors.textPrimary, fontFamily: theme.typography.fontFamily }} className="relative w-[1080px] h-[1350px] flex flex-col shadow-2xl overflow-hidden shrink-0 select-auto">
      <style dangerouslySetInnerHTML={{ __html: customFontsCSS }} />
      {slide.options?.backgroundImage && <div className="absolute inset-0 z-0 w-full h-full pointer-events-none"><img src={slide.options.backgroundImage} className="w-full h-full object-cover" alt="" /></div>}
      {renderLayout()}
      {renderFloatingOverlays()}
      {renderFX()}
    </div>
  )
}

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
