const SafeTextArea = ({ value, onChange, className, placeholder }: { value: string, onChange: (val: string) => void, className?: string, placeholder?: string }) => {
  const [localValue, setLocalValue] = useState(value);
  useEffect(() => { if (value !== localValue) setLocalValue(value); }, [value]);
  return (<textarea value={localValue} onChange={(e) => { setLocalValue(e.target.value); onChange(e.target.value); }} className={className} placeholder={placeholder} />);
};

const TransformControl = ({ label, value, min, max, step, onChange, highlight = false }: { label: string, value: number, min: number, max: number, step: number, onChange: (v: number) => void, highlight?: boolean }) => (
  <div className={`flex flex-col gap-1.5 flex-1 p-2 rounded-xl transition-colors ${highlight ? 'bg-brand/5 border border-brand/10' : ''}`}>
    <div className="flex justify-between px-1">
      <span className={`text-[9px] font-bold uppercase tracking-tighter ${highlight ? 'text-brand' : 'text-zinc-500'}`}>{label}</span>
      <span className={`text-[9px] font-mono ${highlight ? 'text-brand' : 'text-zinc-400'}`}>{value.toFixed(step === 1 ? 0 : 2)}</span>
    </div>
    <input type="range" min={min} max={max} step={step} value={value} onChange={(e) => onChange(parseFloat(e.target.value))} className={`w-full h-1 rounded-lg appearance-none cursor-pointer bg-zinc-800 accent-brand`} />
  </div>
);

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'TEMPLATES' | 'BLOCKS' | 'DESIGN' | 'FX' | 'ASSETS' | 'JSON'>('TEMPLATES');
  const [dslInput, setDslInput] = useState(INITIAL_DSL);
  const [carousel, setCarousel] = useState<ValidatedCarousel | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [zoom, setZoom] = useState(0.40);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);
  const [brandPresets, setBrandPresets] = useState<any[]>(DEFAULT_BRAND_PRESETS);
  const [selectedOverlayId, setSelectedOverlayId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLDivElement>(null);
  const bgImageInputRef = useRef<HTMLInputElement>(null);
  const templateImageInputRef = useRef<HTMLInputElement>(null);
  const overlayImageInputRef = useRef<HTMLInputElement>(null);

  const currentSlide = useMemo(() => carousel?.slides[currentIndex], [carousel, currentIndex]);
  const imageConfig = useMemo(() => currentSlide?.image, [currentSlide]);
  const currentOverlays = useMemo(() => currentSlide?.overlays || [], [currentSlide]);
  const activeOverlay = useMemo(() => currentOverlays.find(o => o.id === selectedOverlayId), [currentOverlays, selectedOverlayId]);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  const updateSlideProperties = useCallback((updates: { path: (string | number)[], value: any }[]) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        if (!parsed.slides[currentIndex]) return prev;
        updates.forEach(({ path, value }) => {
          let target = parsed.slides[currentIndex];
          for (let i = 0; i < path.length - 1; i++) {
            const key = path[i];
            if (!target[key] || typeof target[key] !== 'object') target[key] = Array.isArray(value) ? [] : {};
            target = target[key];
          }
          target[path[path.length - 1]] = value;
        });
        return JSON.stringify(parsed, null, 2);
      } catch (e) { return prev; }
    });
  }, [currentIndex]);

  const updateSlideProperty = useCallback((path: (string | number)[], value: any) => {
    updateSlideProperties([{ path, value }]);
  }, [updateSlideProperties]);

  const addOverlay = useCallback((url: string) => {
    const newId = crypto.randomUUID();
    const newOverlay: OverlayImageConfig = { id: newId, url, x: 0, y: 0, scale: 1, rotation: 0, opacity: 1 };
    const nextOverlays = [...currentOverlays, newOverlay];
    updateSlideProperty(['overlays'], nextOverlays);
    setSelectedOverlayId(newId);
    showToast("Novo Overlay Adicionado!");
  }, [currentOverlays, updateSlideProperty, showToast]);

  const removeOverlay = (id: string) => {
    const next = currentOverlays.filter(o => o.id !== id);
    updateSlideProperty(['overlays'], next);
    if (selectedOverlayId === id) setSelectedOverlayId(null);
    showToast("Objeto removido.");
  };

  const updateActiveOverlay = (key: keyof OverlayImageConfig, val: any) => {
    if (!selectedOverlayId) return;
    const idx = currentOverlays.findIndex(o => o.id === selectedOverlayId);
    if (idx === -1) return;
    updateSlideProperty(['overlays', idx, key], val);
  };

  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      const items = e.clipboardData?.items;
      if (!items) return;
      for (let i = 0; i < items.length; i++) {
        if (items[i].type.indexOf('image') !== -1) {
          const blob = items[i].getAsFile();
          if (!blob) continue;
          const reader = new FileReader();
          reader.onload = (event) => {
            const result = event.target?.result as string;
            // Se estiver com o mouse sobre o preview do template, cola lá. Senão, adiciona overlay.
            const isHoveringTemplate = document.querySelector('.template-preview:hover');
            if (isHoveringTemplate) {
              updateSlideProperty(['image', 'url'], result);
              showToast("Imagem do Template atualizada!");
            } else {
              addOverlay(result);
            }
          };
          reader.readAsDataURL(blob);
          e.preventDefault();
        }
      }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [addOverlay, updateSlideProperty, showToast]);

  useEffect(() => {
    try {
      const parsed = JSON.parse(dslInput);
      const result = carouselSchema.safeParse(parsed);
      if (result.success) { setCarousel(result.data); setError(null); }
      else { setError("Erro no DSL"); }
    } catch (e: any) { setError(e.message); }
