  return (
    <div className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden">
      {toast && <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-8 py-4 rounded-3xl bg-brand text-black font-black uppercase shadow-2xl animate-in slide-in-from-bottom-4`}>{toast.message}</div>}

      <input type="file" ref={bgImageInputRef} onChange={(e) => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => updateSlideProperty(['options', 'backgroundImage'], ev.target?.result as string); r.readAsDataURL(f); } }} className="hidden" accept="image/*" />
      <input type="file" ref={templateImageInputRef} onChange={(e) => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => updateSlideProperty(['image', 'url'], ev.target?.result as string); r.readAsDataURL(f); } }} className="hidden" accept="image/*" />
      <input type="file" ref={overlayImageInputRef} onChange={(e) => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => addOverlay(ev.target?.result as string); r.readAsDataURL(f); } }} className="hidden" accept="image/*" />

      <aside className="w-[440px] border-r border-white/5 flex flex-col bg-zinc-900/50 backdrop-blur-2xl z-20 shrink-0">
