           <nav className="flex gap-1 p-1 bg-black/40 rounded-xl">
              {[
                { id: 'TEMPLATES', icon: Library },
                { id: 'BLOCKS', icon: Type },
                { id: 'DESIGN', icon: Palette },
                { id: 'FX', icon: Sparkles },
                { id: 'ASSETS', icon: ImageIcon },
                { id: 'JSON', icon: FileJson },
              ].map(tab => (<button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 py-3 rounded-lg flex items-center justify-center transition-all ${activeTab === tab.id ? 'bg-zinc-800 text-brand' : 'text-zinc-500 hover:text-white'}`}><tab.icon size={16} /></button>))}
           </nav>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-10">
          {activeTab === 'ASSETS' ? (
            <div className="space-y-10 animate-in slide-in-from-left-4">
              <section className="space-y-4">
                <div className="flex items-center gap-2"><Monitor size={16} className="text-brand" /><h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-100">Imagem do Template</h3></div>
                <div 
                  onClick={() => templateImageInputRef.current?.click()}
                  className="template-preview relative aspect-video rounded-3xl bg-zinc-950 border-2 border-white/5 overflow-hidden group cursor-pointer hover:border-brand/40 transition-all"
                >
                  {imageConfig?.url ? <img src={imageConfig.url} className="w-full h-full object-contain" /> : <div className="w-full h-full flex flex-col items-center justify-center text-zinc-700"><ImagePlus size={32}/><span className="text-[8px] font-black uppercase">Add / Cola Imagem</span></div>}
                  <div className="absolute inset-0 bg-brand/5 opacity-0 group-hover:opacity-100 transition-opacity" />
                </div>
                {imageConfig && (
                  <div className="grid grid-cols-4 gap-2">{IMAGE_TYPE_PRESETS.map(p => (<button key={p.id} onClick={() => updateSlideProperty(['image', 'type'], p.id)} className={`p-3 rounded-xl border transition-all ${imageConfig.type === p.id ? 'bg-brand text-black border-brand' : 'bg-black/40 border-white/5 text-zinc-500'}`} title={p.label}><p.icon size={16}/></button>))}</div>
                )}
              </section>

              <section className="space-y-6 pt-6 border-t border-white/5">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2"><Ghost size={16} className="text-brand" /><h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-100">Objetos Flutuantes (Overlays)</h3></div>
                </div>

                <div 
                  onClick={() => overlayImageInputRef.current?.click()}
                  className="w-full h-32 border-2 border-dashed border-brand/20 rounded-3xl flex flex-col items-center justify-center gap-2 text-brand/40 hover:border-brand/60 hover:text-brand transition-all cursor-pointer group"
                >
                  <ClipboardPaste size={24} className="group-hover:scale-110 transition-transform" />
