                </div>

                {currentOverlays.length > 0 && (
                  <div className="space-y-4">
                    <span className="text-[9px] font-black text-zinc-500 uppercase px-1">Camadas na Cena</span>
                    <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                      {currentOverlays.map((ov) => (
                        <button 
                          key={ov.id} 
                          onClick={() => setSelectedOverlayId(ov.id)}
                          className={`relative w-16 h-16 rounded-2xl border-2 shrink-0 transition-all overflow-hidden ${selectedOverlayId === ov.id ? 'border-brand scale-110 shadow-lg' : 'border-white/5 opacity-60 hover:opacity-100'}`}
                        >
                          <img src={ov.url} className="w-full h-full object-cover" />
                          <button 
                            onClick={(e) => { e.stopPropagation(); removeOverlay(ov.id); }} 
                            className="absolute top-0 right-0 p-1 bg-red-500 text-white opacity-0 group-hover:opacity-100 hover:bg-red-600 transition-opacity"
