                         <div className="grid grid-cols-2 gap-4">
                            <TransformControl label="X" value={activeOverlay.x || 0} min={-1200} max={1200} step={1} onChange={v => updateActiveOverlay('x', v)} highlight />
                            <TransformControl label="Y" value={activeOverlay.y || 0} min={-1200} max={1200} step={1} onChange={v => updateActiveOverlay('y', v)} highlight />
