                            <TransformControl label="Scale" value={activeOverlay.scale || 1} min={0.1} max={8} step={0.05} onChange={v => updateActiveOverlay('scale', v)} highlight />
                            <TransformControl label="Giro" value={activeOverlay.rotation || 0} min={-360} max={360} step={1} onChange={v => updateActiveOverlay('rotation', v)} highlight />
