                            >
                              <MoveHorizontal size={14} /><span className="text-[9px] font-black uppercase">Espelhar</span>
                            </button>
                            <TransformControl label="Opacidade" value={activeOverlay.opacity ?? 1} min={0} max={1} step={0.01} onChange={v => updateActiveOverlay('opacity', v)} />
                         </div>
                      </div>
                    )}
                  </div>
                )}
              </section>

              <section className="space-y-4 pt-6 border-t border-white/5">
                <div className="flex items-center gap-2"><LayoutTemplate size={16} className="text-brand" /><h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-100">Fundo Global</h3></div>
                <div 
                  onClick={() => bgImageInputRef.current?.click()}
