                >
                  {currentSlide?.options?.backgroundImage ? <img src={currentSlide.options.backgroundImage} className="w-full h-full object-cover" /> : <CloudUpload size={32} className="text-zinc-800" />}
                </div>
              </section>
            </div>
          ) : activeTab === 'BLOCKS' ? (
            <div className="space-y-6 animate-in slide-in-from-left-4">
              {currentSlide?.blocks.map((block, idx) => (
                <div key={idx} className="bg-black/40 border border-white/5 rounded-3xl p-5 space-y-4 group">
                   <div className="flex items-center justify-between"><span className="text-[9px] font-black uppercase text-zinc-500">{block.type}</span><button onClick={() => { const n = [...currentSlide.blocks]; n.splice(idx, 1); updateSlideProperty(['blocks'], n); }} className="opacity-0 group-hover:opacity-100 text-red-500"><Trash2 size={14}/></button></div>
                   <SafeTextArea value={(Array.isArray(block.content) ? block.content.join('\n') : block.content as string) || ''} onChange={(val) => updateSlideProperty(['blocks', idx, 'content'], block.type === 'LIST' ? val.split('\n') : val)} className="w-full bg-black/60 border border-white/5 rounded-xl p-3 text-[12px] font-medium text-white outline-none focus:border-brand/50 min-h-[80px]" />
                </div>
              ))}
              <button onClick={() => { const n = [...currentSlide!.blocks, { type: 'PARAGRAPH', content: 'Novo parágrafo...', options: { fontSize: 32 } }]; updateSlideProperty(['blocks'], n); }} className="w-full py-8 border-2 border-dashed border-white/5 rounded-[32px] text-zinc-500 hover:text-brand hover:border-brand/20 transition-all uppercase text-[9px] font-black">Adicionar Bloco</button>
            </div>
          ) : activeTab === 'DESIGN' ? (
            <div className="space-y-10 animate-in slide-in-from-left-4">
               <section className="space-y-6">
                 <div className="flex items-center gap-2"><Baseline size={16} className="text-brand" /><h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-100">Cores Mestras</h3></div>
                 <div className="grid grid-cols-1 gap-6">
                    <div className="flex items-center justify-between p-4 bg-black/40 rounded-2xl border border-white/5"><span className="text-[10px] font-black uppercase">Fundo do Slide</span><input type="color" value={currentSlide?.options?.background || '#0D0D0D'} onChange={e => updateSlideProperty(['options', 'background'], e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer" /></div>
                    <div className="flex items-center justify-between p-4 bg-black/40 rounded-2xl border border-white/5"><span className="text-[10px] font-black uppercase">Cor Principal</span><input type="color" value={currentSlide?.options?.accent || '#1fb2f7'} onChange={e => updateSlideProperty(['options', 'accent'], e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer" /></div>
                 </div>
               </section>
               <section className="space-y-6 pt-6 border-t border-white/5">
                  <div className="flex items-center gap-2"><Type size={16} className="text-brand" /><h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-100">Tipografia</h3></div>
                  <select value={currentSlide?.options?.fontPadrão || 'Inter'} onChange={e => updateSlideProperty(['options', 'fontPadrão'], e.target.value)} className="w-full bg-black/60 border border-white/5 rounded-xl py-3 px-4 text-xs font-bold text-white">{GOOGLE_FONTS.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}</select>
               </select>
            </div>
          ) : activeTab === 'TEMPLATES' ? (
            <div className="grid grid-cols-1 gap-2">{templateRegistry.getAll().map(tpl => (<button key={tpl.name} onClick={() => updateSlideProperty(['template'], tpl.name)} className={`w-full p-4 border rounded-2xl flex items-center gap-4 transition-all ${currentSlide?.template === tpl.name ? 'bg-brand/10 border-brand' : 'bg-white/5 border-white/5 hover:border-white/10'}`}><div className={`w-10 h-10 rounded-xl flex items-center justify-center ${currentSlide?.template === tpl.name ? 'bg-brand text-black' : 'bg-black text-zinc-600'}`}><Library size={18}/></div><div className="text-left font-black uppercase text-[10px]">{tpl.name.replace(/_/g, ' ')}</div></button>))}</div>
          ) : activeTab === 'JSON' ? (
            <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="w-full h-[600px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-2xl outline-none" spellCheck={false} />
          ) : null}
        </div>

        <footer className="p-5 border-t border-white/5 bg-zinc-950">
          <button onClick={async () => {
            if (!carousel || !canvasRef.current) return;
            showToast("Gerando Carrossel...");
            const dataUrl = await captureJpeg(canvasRef.current);
            await downloadZip([{ name: 'slide-1.jpg', dataUrl }], 'projeto.zip', dslInput);
            showToast("Exportado com sucesso!");
          }} className="w-full py-4 bg-brand text-black font-black rounded-xl text-[10px] uppercase shadow-lg flex items-center justify-center gap-3"><Download size={16} strokeWidth={3} /> Gerar Carrossel</button>
        </footer>
      </aside>

      <main className="flex-1 bg-[#121214] relative flex flex-col items-center justify-center">
        {error && <div className="absolute top-5 z-[100] bg-red-500 text-white px-6 py-2 rounded-full flex items-center gap-2 text-[10px] font-black uppercase shadow-2xl animate-in slide-in-from-top-4"><AlertCircle size={14}/> {error}</div>}
        <div className="absolute top-6 left-6 z-40 flex items-center gap-1 bg-black/30 backdrop-blur-xl p-1.5 rounded-xl border border-white/5"><button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-1.5 text-zinc-500 hover:text-white"><ZoomOut size={16} /></button><div className="px-2 text-[10px] font-black font-mono text-zinc-400">{(zoom * 100).toFixed(0)}%</div><button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-1.5 text-zinc-500 hover:text-white"><ZoomIn size={16} /></button></div>

        <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_60px_150px_rgba(0,0,0,0.8)]">
          {currentSlide && <SlideCanvas slide={currentSlide} index={currentIndex} canvasRef={canvasRef} customFonts={carousel?.customFonts} />}
        </div>

        {carousel && (
          <div className="absolute bottom-6 flex items-center gap-4 bg-black/50 backdrop-blur-2xl px-6 py-3 rounded-full border border-white/5">
             <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-0 transition-all"><ChevronLeft size={20}/></button>
             <div className="flex gap-2">
                {carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-1.5 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-brand' : 'w-2 bg-white/10'}`} />))}
             </div>
             <button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-0 transition-all"><ChevronRight size={20}/></button>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export type BlockType = 'TITLE' | 'LIST' | 'IMAGE' | 'SPACER' | 'PARAGRAPH' | 'CARD' | 'BADGE' | 'BOX' | 'USER';

export interface Block {
  type: BlockType;
  content?: string | string[];
  options?: {
    highlight?: string;
    variant?: 'default' | 'accent' | 'muted' | 'box' | 'ghost' | 'outlined' | 'pill' | 'oval' | 'check-list' | 'twitter-post';
    size?: 'sm' | 'md' | 'lg';
    icon?: string;
    customIcon?: string; 
    align?: 'left' | 'center' | 'right';
